module top_module(input clk, rst, input di, input hld, output reg q = 0);reg q1 = 0;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (rst) begin
		q <= 0;
    q1 <= 0;
	end else begin
    if (~hld) begin
      q <= q1;
      q1 <= di;
    end
  end
end

endmodule
